def startup_menu():

    pygame.init()

    WIDTH = 900
    HEIGHT = 650

    screen = pygame.display.set_mode((WIDTH, HEIGHT))

    pygame.display.set_caption("Gelbooru Viewer")

    clock = pygame.time.Clock()

    title_font = pygame.font.SysFont("Segoe UI", 42, bold=True)
    label_font = pygame.font.SysFont("Segoe UI", 24)
    text_font = pygame.font.SysFont("Consolas", 24)

    settings = {

        "tags":"",

        "limit":"100",

        "randomize":True,

        "sortscore":True

    }

    active = "tags"

    cursor = {

        "tags": len(settings["tags"]),

        "limit": len(settings["limit"])

    }

    active = "tags"

    # ---------------- Rectangles ----------------

    tag_box = pygame.Rect(60,120,780,45)

    limit_box = pygame.Rect(60,220,200,45)

    start_button = pygame.Rect(280,560,340,55)

    checkboxes = {

        "randomize":pygame.Rect(60,330,22,22),

        "sortscore":pygame.Rect(60,370,22,22),

    }

    while True:

        mouse = pygame.mouse.get_pos()

        screen.fill((30,30,30))

        # --------------------------------------------------

        pygame.draw.rect(
            screen,
            (45,45,45),
            (25,25,850,600),
            border_radius=12
        )

        title = title_font.render(
            "Gelbooru Viewer",
            True,
            (255,255,255)
        )

        screen.blit(title,(50,30))

        # ---------------- Tags ----------------

        screen.blit(

            label_font.render("Tags",True,(220,220,220)),

            (60,85)

        )

        pygame.draw.rect(

            screen,

            (90,160,255) if active=="tags" else (120,120,120),

            tag_box,

            2,

            border_radius=6

        )

        tag_surface = text_font.render(
            settings["tags"],
            True,
            (255,255,255)
        )

        screen.blit(tag_surface, (70,129))

        if active == "tags":

            if (pygame.time.get_ticks() // 500) % 2 == 0:

                prefix = settings["tags"][:cursor["tags"]]

                cursor_x = 70 + text_font.size(prefix)[0]

                pygame.draw.line(
                    screen,
                    (255,255,255),
                    (cursor_x,130),
                    (cursor_x,155),
                    2
                )

        # ---------------- Limit ----------------

        screen.blit(

            label_font.render("Max Images (Limit)",True,(220,220,220)),

            (60,185)

        )

        pygame.draw.rect(

            screen,

            (90,160,255) if active=="limit" else (120,120,120),

            limit_box,

            2,

            border_radius=6

        )

        screen.blit(

            text_font.render(settings["limit"],True,(255,255,255)),

            (70,229)

        )

        # ---------------- Checkboxes ----------------

        y = 330

        for key,title in [

            ("randomize","Randomize Order"),

            ("sortscore","Sort by Score"),

        ]:

            box = checkboxes[key]

            pygame.draw.rect(

                screen,

                (220,220,220),

                box,

                2

            )

            if settings[key]:

                pygame.draw.rect(

                    screen,

                    (70,180,255),

                    box.inflate(-6,-6)

                )

            screen.blit(

                label_font.render(title,True,(220,220,220)),

                (95,y-3)

            )

            y += 40

        # ---------------- Start Button ----------------

        colour = (70,150,255)

        if start_button.collidepoint(mouse):

            colour=(90,180,255)

        pygame.draw.rect(

            screen,

            colour,

            start_button,

            border_radius=8

        )

        txt = title_font.render(

            "Start Slideshow",

            True,

            (255,255,255)

        )

        screen.blit(

            txt,

            txt.get_rect(center=start_button.center)

        )

        pygame.display.flip()

        # ==================================================

        for event in pygame.event.get():

            if event.type==pygame.QUIT:

                pygame.quit()

                raise SystemExit

            if event.type==pygame.MOUSEBUTTONDOWN:

                if tag_box.collidepoint(event.pos):

                    active = "tags"

                    rel_x = event.pos[0] - 70

                    cursor["tags"] = len(settings["tags"])

                    for i in range(len(settings["tags"]) + 1):

                        if text_font.size(settings["tags"][:i])[0] >= rel_x:

                            cursor["tags"] = i

                            break

                if limit_box.collidepoint(event.pos):

                    active = "limit"

                    rel_x = event.pos[0] - 70

                    cursor["limit"] = len(settings["limit"])

                    for i in range(len(settings["limit"]) + 1):

                        if text_font.size(settings["limit"][:i])[0] >= rel_x:

                            cursor["limit"] = i

                            break

                elif start_button.collidepoint(event.pos):

                    if settings["tags"]=="":

                        settings["tags"]="landscape"

                    try:

                        settings["limit"]=max(

                            1,

                            int(settings["limit"])

                        )

                    except:

                        settings["limit"]=100

                    return settings

                else:

                    for key,box in checkboxes.items():

                        if box.collidepoint(event.pos):

                            settings[key]=not settings[key]

            if event.type==pygame.KEYDOWN:

                if event.key==pygame.K_ESCAPE:

                    pygame.quit()

                    raise SystemExit

                elif event.key==pygame.K_TAB:

                    active="limit" if active=="tags" else "tags"

                elif event.key==pygame.K_RETURN:

                    if settings["tags"]=="":

                        settings["tags"]="landscape"

                    try:

                        settings["limit"]=max(

                            1,

                            int(settings["limit"])

                        )

                    except:

                        settings["limit"]=100

                    return settings

                elif event.key==pygame.K_BACKSPACE:

                    settings[active]=settings[active][:-1]

                else:

                    text = settings[active]
                    pos = cursor[active]

                    mods = pygame.key.get_mods()

                    # --------------------
                    # Clipboard
                    # --------------------

                    if mods & pygame.KMOD_CTRL:

                        if event.key == pygame.K_v:

                            paste = pyperclip.paste()

                            if active == "limit":

                                paste = "".join(c for c in paste if c.isdigit())

                            text = text[:pos] + paste + text[pos:]

                            cursor[active] += len(paste)

                        elif event.key == pygame.K_c:

                            pyperclip.copy(text)

                        elif event.key == pygame.K_x:

                            pyperclip.copy(text)

                            text = ""

                            cursor[active] = 0

                        elif event.key == pygame.K_a:

                            cursor[active] = len(text)

                    # --------------------
                    # Cursor movement
                    # --------------------

                    elif event.key == pygame.K_LEFT:

                        cursor[active] = max(
                            0,
                            cursor[active]-1
                        )

                    elif event.key == pygame.K_RIGHT:

                        cursor[active] = min(
                            len(text),
                            cursor[active]+1
                        )

                    # --------------------
                    # Delete
                    # --------------------

                    elif event.key == pygame.K_DELETE:

                        if cursor[active] < len(text):

                            text = (

                                text[:cursor[active]]

                                +

                                text[cursor[active]+1:]

                            )

                    # --------------------
                    # Backspace
                    # --------------------

                    elif event.key == pygame.K_BACKSPACE:

                        if cursor[active] > 0:

                            text = (

                                text[:cursor[active]-1]

                                +

                                text[cursor[active]:]

                            )

                            cursor[active] -= 1

                    # --------------------
                    # Typing
                    # --------------------

                    else:

                        if event.unicode.isprintable():

                            if active == "limit":

                                if not event.unicode.isdigit():

                                    settings[active] = text

                                    continue

                            text = (

                                text[:cursor[active]]

                                +

                                event.unicode

                                +

                                text[cursor[active]:]

                            )

                            cursor[active] += 1

                    settings[active] = text

        clock.tick(144)

# ============================================================
# API CLIENT
# ============================================================

class GelbooruClient:

    def __init__(self):

        self.api = "https://gelbooru.com/index.php"

    def latest_posts(self, tag, limit, randomize, sortscore):
        
        if sortscore:
            tag += " sort:score"

        params = {

            "page":"dapi",
            "s":"post",
            "q":"index",
            "json":"1",

            "tags":tag,
            "limit":limit,

            "user_id":USER_ID,
            "api_key":API_KEY,

        }

        print("Requesting latest posts...")

        r = session.get(
            self.api,
            params=params,
            timeout=30
        )

        print(r.url)

        r.raise_for_status()

        data = r.json()

        posts = data.get("post", [])

        good = []

        for post in posts:

            url = post.get("file_url")

            if not url:
                continue

            lower = url.lower()

            if lower.endswith(UNSUPPORTED_EXTENSIONS):
                continue

            if not lower.endswith(SUPPORTED_EXTENSIONS):
                continue

            good.append(post)

        if randomize:
            random.shuffle(good)

        print()

        print(f"Found {len(good)} usable posts.")

        return good

# ============================================================
# IMAGE CACHE
# ============================================================

class ImageCache:

    def __init__(self):

        self.memory = {}

        self.lock = threading.Lock()

    def has(self,url):

        with self.lock:

            return url in self.memory

    def get(self,url):

        with self.lock:

            return self.memory.get(url)

    def put(self,url,image):

        with self.lock:

            self.memory[url]=image

    def disk_name(self,url):

        md5 = hashlib.md5(url.encode()).hexdigest()

        ext = os.path.splitext(url)[1]

        return CACHE_FOLDER / f"{md5}{ext}"

cache = ImageCache()

# ============================================================
# DOWNLOAD IMAGE
# ============================================================

def download_image(url):

    filename = cache.disk_name(url)

    # ------------------------------
    # Already cached on disk
    # ------------------------------

    if filename.exists():

        try:

            img = Image.open(filename)

            img.thumbnail(
                MAX_IMAGE_SIZE,
                Image.Resampling.LANCZOS
            )

            return img.convert("RGB")

        except Exception:

            filename.unlink(missing_ok=True)

    # ------------------------------
    # Download
    # ------------------------------

    r = session.get(
        url,
        timeout=30
    )

    if r.status_code != 200:

        raise RuntimeError(
            f"HTTP {r.status_code}"
        )

    content_type = r.headers.get(
        "Content-Type",
        ""
    )

    if not content_type.startswith("image/"):

        raise RuntimeError(
            f"Server returned {content_type}"
        )

    img = Image.open(
        io.BytesIO(r.content)
    )

    img.thumbnail(
        MAX_IMAGE_SIZE,
        Image.Resampling.LANCZOS
    )

    try:

        img.save(filename)

    except Exception:

        pass

    return img.convert("RGB")

# ============================================================
# CONVERT TO PYGAME
# ============================================================

def pillow_to_surface(img):

    return pygame.image.fromstring(

        img.tobytes(),

        img.size,

        img.mode

    )

# ============================================================
# SCALE TO SCREEN
# ============================================================

def fit_surface(surface,width,height):

    sw = surface.get_width()
    sh = surface.get_height()

    scale = min(

        width/sw,

        height/sh

    )

    nw = int(sw*scale)
    nh = int(sh*scale)

    return pygame.transform.smoothscale(
        surface,
        (nw,nh)
    )

# ============================================================
# PRELOADER
# ============================================================

class Preloader(threading.Thread):

    def __init__(self, posts):

        super().__init__(daemon=True)

        self.posts = posts

        self.running = True

        self.queue = queue.Queue()

        self.failed = set()

        self.total_loaded = 0

        self.current_index = 0

    # --------------------------------------------------------

    def set_index(self, index):

        self.current_index = index

        wanted = []

        for i in range(PRELOAD_COUNT):

            wanted.append(
                (index + i) % len(self.posts)
            )

        queued = set()

        while not self.queue.empty():

            try:
                queued.add(self.queue.get_nowait())
            except queue.Empty:
                break

        for i in wanted:

            if i in queued:
                continue

            self.queue.put(i)

    # --------------------------------------------------------

    def stop(self):

        self.running = False

    # --------------------------------------------------------

    def run(self):

        while self.running:

            try:

                index = self.queue.get(timeout=0.25)

            except queue.Empty:

                continue

            post = self.posts[index]

            url = post["file_url"]

            if url in self.failed:
                continue

            if cache.has(url):
                continue

            try:

                image = download_image(url)

                surface = pillow_to_surface(image)

                cache.put(url, surface)

                self.total_loaded += 1

                print(
                    f"Cached {self.total_loaded}/{len(self.posts)}"
                )

            except Exception as e:

                self.failed.add(url)

                print("Preload skipped:", e)

# ============================================================
# VIEW CACHE ACCESS
# ============================================================

def get_surface(post):

    url = post["file_url"]

    image = cache.get(url)

    if image is not None:
        return image

    try:

        image = pillow_to_surface(
            download_image(url)
        )

        cache.put(url, image)

        return image

    except Exception as e:

        print("Failed:", e)

        return None

# ============================================================
# FADE TRANSITION
# ============================================================

def fade(screen, old, new, speed):

    if old is None:

        screen.fill(BACKGROUND)

        rect = new.get_rect(
            center=screen.get_rect().center
        )

        screen.blit(new, rect)

        pygame.display.flip()

        return

    clock = pygame.time.Clock()

    start = pygame.time.get_ticks()

    while True:

        elapsed = pygame.time.get_ticks() - start

        alpha = min(
            255,
            int(elapsed / speed * 255)
        )

        old.set_alpha(255 - alpha)

        new.set_alpha(alpha)

        screen.fill(BACKGROUND)

        r1 = old.get_rect(
            center=screen.get_rect().center
        )

        r2 = new.get_rect(
            center=screen.get_rect().center
        )

        screen.blit(old, r1)

        screen.blit(new, r2)

        pygame.display.flip()

        if alpha >= 255:
            break

        clock.tick(120)

    old.set_alpha(None)
    new.set_alpha(None)

