# ============================================================
# OVERLAY
# ============================================================

def draw_overlay(

    screen,

    tag,

    index,

    total,

    auto,

    delay,

    preloader,

    fade

):

    if not SHOW_OVERLAY:
        return

    lines = [

        f"Tag: {tag}",

        f"Image: {index+1}/{total}",

        f"Cached: {len(cache.memory)}",

        f"Downloaded: {preloader.total_loaded}",

        f"Auto-scroll: {'ON' if auto else 'OFF'}",

        "R = Toggle Auto-scroll",

        f"Delay: {delay:.2f}s",

        "+/- = Speed",

        f"Fade: {'ON' if fade else 'OFF'}",

        "F = Toggle Fade",

        "TAB = Overlay"
    
    ]

    width = 0

    rendered = []

    for line in lines:

        surf = overlay_font.render(
            line,
            True,
            (255,255,255)
        )

        rendered.append(surf)

        width = max(width, surf.get_width())

    panel = pygame.Surface(
        (
            width + 30,
            len(rendered)*30 + 20
        ),
        pygame.SRCALPHA
    )

    panel.fill((0,0,0,170))

    y = 10

    for surf in rendered:

        panel.blit(
            surf,
            (15,y)
        )

        y += 30

    screen.blit(
        panel,
        (15,15)
    )

# ============================================================
# LOADING SCREEN
# ============================================================

def draw_loading(

    screen,

    text

):

    screen.fill((0,0,0))

    surf = overlay_font.render(
        text,
        True,
        (255,255,255)
    )

    rect = surf.get_rect(
        center=screen.get_rect().center
    )

    screen.blit(
        surf,
        rect
    )

    pygame.display.flip()

# ============================================================
# MAIN APPLICATION
# ============================================================

def main():

    global SHOW_OVERLAY
    global ENABLE_FADE
    global EXCLUDED_TAGS

    pygame.init()

    pygame.display.set_caption(
        "Gelbooru Slideshow Viewer"
    )

    

    # ----------------------------------------
    # Fetch posts
    # ----------------------------------------

    settings = startup_menu()

    tag = settings["tags"] + EXCLUDED_TAGS
    limit = settings["limit"]
    randomize = settings["randomize"]
    sortscore = settings["sortscore"]

    screen = pygame.display.set_mode(
        (0, 0),
        pygame.FULLSCREEN
    )

    screen_width, screen_height = screen.get_size()

    client = GelbooruClient()

    posts = client.latest_posts(
        tag,
        limit,
        randomize,
        sortscore
    )

    if not posts:

        print("No usable posts found.")

        pygame.quit()

        return

    # ----------------------------------------
    # Start preloader
    # ----------------------------------------

    preloader = Preloader(posts)

    preloader.start()

    index = 0

    preloader.set_index(index)

    # ----------------------------------------
    # Wait for first image
    # ----------------------------------------

    draw_loading(
        screen,
        "Loading first image..."
    )

    current = None

    while current is None:

        current = get_surface(
            posts[index]
        )

        if current is None:

            index = (index + 1) % len(posts)

            preloader.set_index(index)

        pygame.time.wait(50)

    current = fit_surface(
        current,
        screen_width,
        screen_height
    )

    clock = pygame.time.Clock()

    running = True

    auto_scroll = False

    auto_delay = AUTO_SCROLL_SECONDS

    last_switch = pygame.time.get_ticks()

    # ----------------------------------------
    # Main loop
    # ----------------------------------------

    while running:

        now = pygame.time.get_ticks()

        # --------------------
        # Auto-scroll
        # --------------------

        if auto_scroll:

            if now - last_switch >= auto_delay * 1000:

                index = (index + 1) % len(posts)

                preloader.set_index(index)

                next_surface = get_surface(
                    posts[index]
                )

                if next_surface:

                    next_surface = fit_surface(
                        next_surface,
                        screen_width,
                        screen_height
                    )

                    if ENABLE_FADE:

                        fade(
                            screen,
                            current,
                            next_surface,
                            FADE_SPEED
                        )

                    current = next_surface

                    last_switch = now

        # --------------------
        # Draw
        # --------------------

        screen.fill(BACKGROUND)

        rect = current.get_rect(
            center=screen.get_rect().center
        )

        screen.blit(
            current,
            rect
        )

        draw_overlay(

            screen,

            tag[:-len(EXCLUDED_TAGS)],

            index,

            len(posts),

            auto_scroll,

            auto_delay,

            preloader,

            ENABLE_FADE

        )

        pygame.display.flip()

        # --------------------
        # Events
        # --------------------

        for event in pygame.event.get():

            if event.type == pygame.QUIT:

                running = False

            elif event.type == pygame.KEYDOWN:

                # ---------------- Quit

                if event.key in (
                    pygame.K_ESCAPE,
                    pygame.K_q
                ):

                    running = False

                # ---------------- Next

                elif event.key in (
                    pygame.K_RIGHT,
                    pygame.K_SPACE
                ):

                    index = (index + 1) % len(posts)

                    preloader.set_index(index)

                    surface = get_surface(
                        posts[index]
                    )

                    if surface:

                        surface = fit_surface(
                            surface,
                            screen_width,
                            screen_height
                        )

                        if ENABLE_FADE:

                            fade(
                                screen,
                                current,
                                surface,
                                FADE_SPEED
                            )

                        current = surface

                        last_switch = pygame.time.get_ticks()

                # ---------------- Previous

                elif event.key == pygame.K_LEFT:

                    index = (index - 1) % len(posts)

                    preloader.set_index(index)

                    surface = get_surface(
                        posts[index]
                    )

                    if surface:

                        surface = fit_surface(
                            surface,
                            screen_width,
                            screen_height
                        )

                        if ENABLE_FADE:

                            fade(
                                screen,
                                current,
                                surface,
                                FADE_SPEED
                            )

                        current = surface

                        last_switch = pygame.time.get_ticks()

                # ---------------- Auto-scroll

                elif event.key == pygame.K_r:

                    auto_scroll = not auto_scroll

                    last_switch = pygame.time.get_ticks()

                    print(
                        "Auto-scroll:",
                        auto_scroll
                    )

                # ---------------- Increase delay

                elif event.key in (
                    pygame.K_EQUALS,
                    pygame.K_PLUS,
                    pygame.K_KP_PLUS
                ):

                    if auto_delay < 0.099:
                        auto_delay += 0.01

                    elif auto_delay < 0.499:
                        auto_delay += 0.05

                    else:
                        auto_delay += 0.1

                    print(
                        auto_delay
                    )

                # ---------------- Decrease delay

                elif event.key in (
                    pygame.K_MINUS,
                    pygame.K_KP_MINUS
                ):
                    
                    if auto_delay < 0.11:
                        auto_delay = max(
                            0.01,
                            auto_delay - 0.01
                        )
                    elif auto_delay < 0.51:
                        auto_delay = max(
                            0.01,
                            auto_delay - 0.05
                        )
                    else:
                        auto_delay = max(
                            0.01,
                            auto_delay - 0.1
                        )

                    print(
                        auto_delay
                    )

                # ---------------- Overlay

                elif event.key == pygame.K_TAB:

                    SHOW_OVERLAY = (
                        not SHOW_OVERLAY
                    )

                # ---------------- Fade

                elif event.key == pygame.K_f:

                    ENABLE_FADE = (
                        not ENABLE_FADE
                    )

        clock.tick(120)

    # ----------------------------------------
    # Shutdown
    # ----------------------------------------

    preloader.stop()

    preloader.join(timeout=2)

    pygame.quit()


# ============================================================
# ENTRY POINT
# ============================================================

if __name__ == "__main__":

    main()
